import pytest

def test_freeze_at_min_and_max_card_id_boundaries(
    api_client, card_at_min_id, card_at_max_id
):
    for card in (card_at_min_id, card_at_max_id):
        card_id = card["id"]
        resp = api_client.post(f"/cards/{card_id}/freeze")
        assert resp.status_code == 200, (
            f"Expected 200 for card_id={card_id}, got {resp.status_code}"
        )
        assert resp.json()["status"] == "frozen"
        # Cleanup: unfreeze to restore state (idempotency)
        api_client.post(f"/cards/{card_id}/unfreeze")
